206	void OpencoreImpl::WriteNtFile(FILE* fp) {
207	    int phnum = (int)phdr.size();
208	    Elf64_Nhdr elf_nhdr;
209	    elf_nhdr.n_namesz = NOTE_CORE_NAME_SZ;
210	    elf_nhdr.n_descsz = sizeof(lp64::File) * phnum + 2 * 8 + RoundUp(fileslen, 4);
211	    elf_nhdr.n_type = NT_FILE;
212	
213	    char magic[8];
214	    memset(magic, 0, sizeof(magic));
215	    snprintf(magic, NOTE_CORE_NAME_SZ, ELFCOREMAGIC);
216	
217	    fwrite(&elf_nhdr, sizeof(Elf64_Nhdr), 1, fp);
218	    fwrite(magic, sizeof(magic), 1, fp);
219	
220	    uint64_t number = phnum;
221	    fwrite(&number, 8, 1, fp);
222	    fwrite(&page_size, 8, 1, fp);
223	
224	    for (int index = 0; index < phnum; ++index)
225	        fwrite(&file[index], sizeof(lp64::File), 1, fp);
226	
227	    for (int index = 0; index < phnum; ++index)
228	        fwrite(maps[index].file.data(), maps[index].file.length() + 1, 1, fp);
229	}
230	
231	void OpencoreImpl::AlignNoteSegment(FILE* fp) {
232	    memset(zero.data(), 0x0, align_size);
233	    uint64_t align_filesz = note.p_filesz - RoundUp(fileslen, 4) + fileslen;
234	    uint64_t offset = RoundUp(note.p_offset + align_filesz, align_size);
235	    uint64_t size = offset - (note.p_offset + align_filesz);
236	    fwrite(zero.data(), size, 1, fp);
237	}
238	
239	void OpencoreImpl::WriteCoreLoadSegment(int pid, FILE* fp) {
240	    char filename[32];
241	    int fd;
242	    int index = 0;
243	    int phnum = (int)phdr.size();
244	    memset(zero.data(), 0x0, align_size);
245	
246	    snprintf(filename, sizeof(filename), "/proc/%d/mem", pid);
247	    fd = open(filename, O_RDONLY);
248	    if (fd < 0) {
249	        JNI_LOGE("open %s fail.", filename);
250	        return;
251	    }
252	
253	    while(index < phnum) {
254	        if (phdr[index].p_filesz > 0) {
255	            long current_pos = ftell(fp);
256	            bool need_padd_zero = false;
257	            int count = phdr[index].p_memsz / align_size;
258	            for (int i = 0; i < count; i++) {
259	                memset(zero.data(), 0x0, align_size);
260	                pread64(fd, zero.data(), phdr[index].p_align, phdr[index].p_vaddr + (i * align_size));
261	                uint64_t ret = fwrite(zero.data(), align_size, 1, fp);
262	                if (ret != 1) {
263	                    JNI_LOGE("[%" PRIx64 "] write load segment fail. %s %s",
264	                            (uint64_t)phdr[index].p_vaddr, strerror(errno), maps[index].file.c_str());
265	                    if (errno == ENOSPC)
266	                        return;
267	
268	                    need_padd_zero = true;
269	                    break;
270	                }
271	            }
272	            if (need_padd_zero && current_pos > 0) {
273	                memset(zero.data(), 0x0, align_size);
274	                fseek(fp, current_pos, SEEK_SET);
275	                int count = phdr[index].p_memsz / align_size;
276	                for (int i = 0; i < count; i++)
277	                    fwrite(zero.data(), align_size, 1, fp);
278	            }
279	        }
280	        index++;
281	    }
282	    close(fd);
283	}
284	
285	bool OpencoreImpl::DoCoredump(const char* filename) {
286	    Prepare(filename);
287	
288	    FILE* fp = fopen(filename, "wb");
289	    if (!fp) {
290	        JNI_LOGE("%s %s: %s", __func__, filename, strerror(errno));
291	        return false;
292	    }
293	
294	    StopTheWorld(getPid());
295	
296	    ParseProcessMapsVma(getPid());
297	    CreateCoreHeader();
298	    CreateCoreNoteHeader();
299	    CreateCorePrStatus(getPid());
300	    CreateCoreAUXV(getPid());
301	    SpecialCoreFilter();
302	
303	    // ELF Header
304	    WriteCoreHeader(fp);
305	
306	    // Program Headers
307	    WriteCoreNoteHeader(fp);
308	    WriteCoreProgramHeaders(fp);
309	
310	    // Segments
311	    WriteCorePrStatus(fp);
312	    WriteCoreAUXV(fp);
313	    WriteNtFile(fp);
314	    AlignNoteSegment(fp);
315	    WriteCoreLoadSegment(getPid(), fp);
316	
317	    fflush(fp);
318	    fsync(fileno(fp));
319	    fclose(fp);
320	    return true;
321	}
322	
323	int OpencoreImpl::NeedFilterFile(Opencore::VirtualMemoryArea& vma) {
324	    struct stat sb;
325	    int fd = open(vma.file.c_str(), O_RDONLY);
326	    if (fd < 0)
327	        return VMA_NULL;
328	
329	    if (fstat(fd, &sb) < 0) {
330	        close(fd);
331	        return VMA_NULL;
332	    }
333	
334	    char* mem = (char *)mmap(NULL, sb.st_size, PROT_READ, MAP_PRIVATE, fd, 0x0);
335	    close(fd);
336	    if (mem == MAP_FAILED)
337	        return VMA_NULL;
338	
339	    Elf64_Ehdr* ehdr = (Elf64_Ehdr*)mem;
340	    if (strncmp(mem, ELFMAG, 4) || ehdr->e_machine != getMachine()) {
341	        munmap(mem, sb.st_size);
342	        return VMA_NULL;
343	    }
344	
345	    int ret = VMA_NULL;
346	    Elf64_Phdr* phdr = (Elf64_Phdr *)(mem + sizeof(Elf64_Ehdr));
347	    for (int index = 0; index < ehdr->e_phnum; index++) {
348	        if (phdr[index].p_type != PT_LOAD)
349	            continue;
350	
351	        int pos = RoundDown(phdr[index].p_offset, page_size);
352	        int end = pos + phdr[index].p_memsz;
353	        if (pos <= vma.offset && vma.offset < end) {
354	            if ((phdr[index].p_flags & PF_W))
355	                ret = VMA_NORMAL;
356	        }
357	    }
358	
359	    munmap(mem, sb.st_size);
360	    return ret;
361	}
362	
363	uint64_t OpencoreImpl::FindAuxv(uint64_t type) {
364	    for (int idx = 0; idx < auxvnum; ++idx) {
365	        if (auxv[idx].type == type)
366	            return auxv[idx].value;
367	    }
368	    return 0;
369	}
370	
371	void OpencoreImpl::Prepare(const char* filename) {
372	    JNI_LOGI("Coredump %s ...", filename);
373	    zero.assign(align_size, 0);
374	    memset(&ehdr, 0, sizeof(Elf64_Ehdr));
375	    memset(&note, 0, sizeof(Elf64_Phdr));
376	}
377	
378	void OpencoreImpl::Finish() {
379	    auxv.clear();
380	    phdr.clear();
381	    file.clear();
382	    zero.clear();
383	    Opencore::Finish();
384	    JNI_LOGI("Finish done.");
385	}
